// // This comment suggests that the multiplexer selects the least significant bit of the input based on the selection signal.
module mux_4to1(
    input [1:0] sel,
    input [7:0] a,
    input [7:0] b,
    input [7:0] c,
    input [7:0] d,
    output reg [7:0] y
);

always @(*)
begin
  case (sel)
    2'b00: y = a;
    2'b01: y = b;
    2'b10: y = c;
    2'b11: y = d;
    default: y = 8'b0;
  endcase
end

endmodule
